gt_raw:
{"name": "", 
"cron": "", 
"period": 0, 
"script": "
original_temp = (#WineCellar #TemperatureSensor).Temperature

delay(10 MIN)

temp = (#WineCellar #TemperatureSensor).Temperature

if (temp >= original_temp + 1 or temp <= original_temp - 1) {

    (#Speaker).Speak("와인셀러의 온도가 급변했습니다")
}"}

